1	import {
2	  Injectable,
3	  NotFoundException,
4	  BadRequestException,
5	  ForbiddenException,
6	} from '@nestjs/common';
7	import { InjectRepository } from '@nestjs/typeorm';
8	import { Repository } from 'typeorm';
9	import { Settlement, SettlementStatus } from '../database/entities/settlement.entity';
10	import { Listing } from '../database/entities/listing.entity';
11	import { User } from '../database/entities/user.entity';
12	import { AuditService } from '../audit/audit.service';
13	import { FreightService } from './freight.service';
14	import { SettlementFiltersDto } from './dto/settlement.dto';
15	import { EncryptionService } from '../common/encryption/encryption.service';
16	import { validateStep1Approval, validateStep2Approval } from './settlement-sod.policy';
17	import { logger } from '../common/logger/winston.logger';
18	
19	/** PG unique-violation error code */
20	const PG_UNIQUE_VIOLATION = '23505';
21	const SCHEDULER_CONTEXT = 'SettlementScheduler';
22	
23	export interface GenerationRunResult {
24	  period: string;
25	  triggeredBy: 'manual' | 'scheduler';
26	  generatedCount: number;
27	  /** Vendors skipped because a statement already existed for the period. */
28	  skippedCount: number;
29	  /** Vendors where generation failed with an unexpected error. */
30	  errorCount: number;
31	  durationMs: number;
32	  settlements: Settlement[];
33	}
34	
35	@Injectable()
36	export class SettlementsService {
37	  constructor(
38	    @InjectRepository(Settlement)
39	    private readonly settlementRepo: Repository<Settlement>,
40	    @InjectRepository(Listing)
41	    private readonly listingRepo: Repository<Listing>,
42	    @InjectRepository(User)
43	    private readonly userRepo: Repository<User>,
44	    private readonly auditService: AuditService,
45	    private readonly freightService: FreightService,
46	    private readonly encryption: EncryptionService,
47	  ) {}
48	
49	  async findAll(
50	    userId: string,
51	    role: string,
52	    filters: SettlementFiltersDto,
53	  ): Promise<Settlement[]> {
54	    const qb = this.settlementRepo.createQueryBuilder('s');
55	
56	    if (role === 'vendor') {
57	      qb.where('s.vendorId = :userId', { userId });
58	    }
59	    if (filters.month) {
60	      qb.andWhere('s.month = :month', { month: filters.month });
61	    }
62	    if (filters.status) {
63	      qb.andWhere('s.status = :status', { status: filters.status });
64	    }
65	
66	    return qb.orderBy('s.createdAt', 'DESC').getMany();
67	  }
68	
69	  async findOne(id: string, userId: string, role: string): Promise<{
70	    settlement: Settlement;
71	    variance: { expected: number; actual: number; variance: number; variancePercent: number };
72	  }> {
73	    const settlement = await this.settlementRepo.findOne({ where: { id } });
74	    if (!settlement) throw new NotFoundException('Settlement not found');
75	    if (role === 'vendor' && settlement.vendorId !== userId) {
76	      throw new ForbiddenException('Access denied to this settlement');
77	    }
78	
79	    const expected = Number(settlement.totalCharges);
80	    const actual = expected;
81	    const variance = actual - expected;
82	    const variancePercent = expected > 0 ? (variance / expected) * 100 : 0;
83	
84	    return {
85	      settlement,
86	      variance: {
87	        expected: round(expected),
88	        actual: round(actual),
89	        variance: round(variance),
90	        variancePercent: round(variancePercent),
91	      },
92	    };
93	  }
94	
95	  /**
96	   * Generates monthly settlement statements for all active vendors.
97	   *
98	   * Safe under retries and concurrent calls:
99	   *   1. Soft check: `findOne` skips vendors that already have a record
100	   *      (fast path, avoids unnecessary work).
101	   *   2. Hard guard: the DB unique index on `(vendorId, month)` catches any
102	   *      race window between the check and the insert.  A PG-23505 error is
103	   *      treated as "already generated" and counted as `skippedCount`.
104	   *
105	   * Vendor-level errors are isolated — a failure for one vendor increments
106	   * `errorCount` but does not abort the rest.
107	   */
108	  async generateMonthly(
109	    month: string,
110	    actorId: string,
111	    triggeredBy: 'manual' | 'scheduler' = 'manual',
112	  ): Promise<GenerationRunResult> {
113	    const startMs = Date.now();
114	    logger.info(`Settlement generation started`, {
115	      context: SCHEDULER_CONTEXT,
116	      period: month,
117	      triggeredBy,
118	    });
119	
120	    const vendors = await this.userRepo.find({ where: { role: 'vendor' as any, isActive: true } });
121	    const settlements: Settlement[] = [];
122	    let skippedCount = 0;
123	    let errorCount = 0;
124	
125	    for (const vendor of vendors) {
126	      // Soft idempotency check — avoids hitting the DB constraint on every retry
127	      const existing = await this.settlementRepo.findOne({
128	        where: { vendorId: vendor.id, month },
129	      });
130	      if (existing) {
131	        skippedCount++;
132	        continue;
133	      }
134	
135	      try {
136	        const saved = await this.generateForVendor(vendor, month, actorId);
137	        settlements.push(saved);
138	      } catch (err: any) {
139	        if (err?.code === PG_UNIQUE_VIOLATION) {
140	          // Concurrent worker saved first — treat as already generated
141	          skippedCount++;
142	        } else {
143	          errorCount++;
144	          logger.error(`Settlement generation failed for vendor ${vendor.id}`, {
145	            context: SCHEDULER_CONTEXT,
146	            period: month,
147	            vendorId: vendor.id,
148	            error: err?.message,
149	          });
150	        }
151	      }
152	    }
153	
154	    const durationMs = Date.now() - startMs;
155	    logger.info(`Settlement generation completed`, {
156	      context: SCHEDULER_CONTEXT,
157	      period: month,
158	      triggeredBy,
159	      generatedCount: settlements.length,
160	      skippedCount,
161	      errorCount,
162	      durationMs,
163	    });
164	
165	    return {
166	      period: month,
167	      triggeredBy,
168	      generatedCount: settlements.length,
169	      skippedCount,
170	      errorCount,
171	      durationMs,
172	      settlements,
173	    };
174	  }
175	
176	  private async generateForVendor(
177	    vendor: User,
178	    month: string,
179	    actorId: string,
180	  ): Promise<Settlement> {
181	    const listings = await this.listingRepo
182	      .createQueryBuilder('l')
183	      .where('l.vendorId = :vendorId', { vendorId: vendor.id })
184	      .andWhere("to_char(l.\"createdAt\", 'YYYY-MM') = :month", { month })
185	      .getMany();
186	
187	    let totalCharges = 0;
188	    for (const listing of listings) {
189	      const freight = this.freightService.calculate({
190	        distanceMiles: 150,
191	        weightLbs: Number(listing.age) * 2 + 5,
192	        dimWeightLbs: 10,
193	        isOversized: false,
194	        isWeekend: false,
195	      });
196	      totalCharges += freight.total;
197	    }
198	
199	    const taxAmount = round(totalCharges * 0.085);
200	
201	    const settlement = this.settlementRepo.create({
202	      vendorId: vendor.id,
203	      month,
204	      totalCharges,
205	      taxAmount,
206	      status: SettlementStatus.PENDING,
207	      data: { listingCount: listings.length },
208	    });
209	    const saved = await this.settlementRepo.save(settlement);
210	
211	    await this.auditService.log({
212	      action: 'settlement.generate',
213	      actorId,
214	      entityType: 'settlement',
215	      entityId: saved.id,
216	      after: { vendorId: vendor.id, month, totalCharges, taxAmount } as unknown as Record<string, unknown>,
217	    });
218	
219	    return saved;
220	  }
221	
222	  async approveStep1(id: string, reviewerId: string, role: string): Promise<Settlement> {
223	    const settlement = await this.settlementRepo.findOne({ where: { id } });
224	    if (!settlement) throw new NotFoundException('Settlement not found');
225	
226	    validateStep1Approval(settlement, role);
227	
228	    const before = { ...settlement } as unknown as Record<string, unknown>;
229	    settlement.status = SettlementStatus.REVIEWER_APPROVED;
230	    settlement.reviewerApprovedBy = reviewerId;
231	    settlement.reviewerApprovedAt = new Date();
232	    const saved = await this.settlementRepo.save(settlement);
233	
234	    await this.auditService.log({
235	      action: 'settlement.approve_step1',
236	      actorId: reviewerId,
237	      entityType: 'settlement',
238	      entityId: id,
239	      before,
240	      after: { ...saved, approvedStep1By: reviewerId, approvedStep1At: saved.reviewerApprovedAt } as unknown as Record<string, unknown>,
241	    });
242	
243	    return saved;
244	  }
245	
246	  async approveStep2(id: string, financeId: string, role: string): Promise<Settlement> {
247	    const settlement = await this.settlementRepo.findOne({ where: { id } });
248	    if (!settlement) throw new NotFoundException('Settlement not found');
249	
250	    validateStep2Approval(settlement, financeId, role);
251	
252	    const before = { ...settlement } as unknown as Record<string, unknown>;
253	    settlement.status = SettlementStatus.FINANCE_APPROVED;
254	    settlement.financeApprovedBy = financeId;
255	    settlement.financeApprovedAt = new Date();
256	    const saved = await this.settlementRepo.save(settlement);
257	
258	    await this.auditService.log({
259	      action: 'settlement.approve_step2',
260	      actorId: financeId,
261	      entityType: 'settlement',
262	      entityId: id,
263	      before,
264	      after: { ...saved, approvedStep2By: financeId, approvedStep2At: saved.financeApprovedAt } as unknown as Record<string, unknown>,
265	    });
266	
267	    return saved;
268	  }
269	
270	  async reject(id: string, actorId: string, role: string, reason: string): Promise<Settlement> {
271	    if (role !== 'ops_reviewer' && role !== 'finance_admin' && role !== 'admin') {
272	      throw new ForbiddenException('Only approver roles can reject settlements');
273	    }
274	
275	    const settlement = await this.settlementRepo.findOne({ where: { id } });
276	    if (!settlement) throw new NotFoundException('Settlement not found');
277	
278	    const before = { ...settlement } as unknown as Record<string, unknown>;
279	    settlement.status = SettlementStatus.REJECTED;
280	    settlement.data = { ...settlement.data, rejectedBy: actorId, rejectedReason: reason };
281	    const saved = await this.settlementRepo.save(settlement);
282	
283	    await this.auditService.log({
284	      action: 'settlement.reject',
285	      actorId,
286	      entityType: 'settlement',
287	      entityId: id,
288	      before,
289	      after: saved as unknown as Record<string, unknown>,
290	    });
291	
292	    return saved;
293	  }
294	
295	  async exportCsv(
296	    id: string,
297	    requesterId: string,
298	    requesterRole: string,
299	    requesterUsername: string,
300	  ): Promise<string> {
301	    const settlement = await this.settlementRepo.findOne({
302	      where: { id },
303	      relations: ['vendor'],
304	    });
305	    if (!settlement) throw new NotFoundException('Settlement not found');
306	    if (requesterRole === 'vendor' && settlement.vendorId !== requesterId) {
307	      throw new ForbiddenException('Access denied to this settlement');
308	    }
309	    if (settlement.status !== SettlementStatus.FINANCE_APPROVED) {
310	      throw new BadRequestException(
311	        `Only fully approved settlements can be exported (current status: ${settlement.status})`,
312	      );
313	    }
314	
315	    const isAdmin = requesterRole === 'admin';
316	    const vendor = settlement.vendor;
317	
318	    const phone = vendor?.deviceFingerprint
319	      ? isAdmin
320	        ? this.encryption.decrypt(vendor.deviceFingerprint)
321	        : '****' + this.encryption.decrypt(vendor.deviceFingerprint).slice(-4)
322	      : 'N/A';
323	
324	    const email = vendor?.email
325	      ? isAdmin
326	        ? this.encryption.decrypt(vendor.email)
327	        : '***masked***'
328	      : 'N/A';
329	
330	    const timestamp = new Date().toISOString();
331	    const rows = [
332	      `"CONFIDENTIAL - ${requesterUsername} - ${timestamp}"`,
333	      'Vendor ID,Vendor Username,Email,Phone,Month,Total Charges,Tax Amount,Status',
334	      [
335	        settlement.vendorId,
336	        vendor?.username ?? 'N/A',
337	        email,
338	        phone,
339	        settlement.month,
340	        settlement.totalCharges,
341	        settlement.taxAmount,
342	        settlement.status,
343	      ]
344	        .map((v) => `"${v}"`)
345	        .join(','),
346	    ];
347	
348	    return rows.join('\n');
349	  }
350	}
351	
352	function round(n: number): number {
353	  return Math.round(n * 100) / 100;
354	}
