1	/**
2	 * settlement-scheduler.test.ts
3	 *
4	 * Tests for:
5	 *   - previousMonthPeriod / isFirstDayOfMonthUTC (pure period utilities)
6	 *   - SettlementSchedulerService.tick() — scheduling logic and deduplication
7	 *   - SettlementsService.generateMonthly() — idempotency under retries,
8	 *     concurrent duplicate handling, and GenerationRunResult shape
9	 */
10	
11	import {
12	  previousMonthPeriod,
13	  isFirstDayOfMonthUTC,
14	} from '../backend/src/settlements/settlement-period';
15	
16	import { SettlementSchedulerService, SCHEDULER_ACTOR_ID } from '../backend/src/settlements/settlement-scheduler.service';
17	import { SettlementsService, GenerationRunResult } from '../backend/src/settlements/settlements.service';
18	import { Repository } from 'typeorm';
19	
20	// ── previousMonthPeriod ───────────────────────────────────────────────────────
21	
22	describe('previousMonthPeriod', () => {
23	  it('February 1st → January of the same year', () => {
24	    expect(previousMonthPeriod(new Date('2024-02-01T00:00:00Z'))).toBe('2024-01');
25	  });
26	
27	  it('January 1st → December of the previous year (year rollover)', () => {
28	    expect(previousMonthPeriod(new Date('2024-01-01T00:00:00Z'))).toBe('2023-12');
29	  });
30	
31	  it('March 1st → February', () => {
32	    expect(previousMonthPeriod(new Date('2024-03-01T12:00:00Z'))).toBe('2024-02');
33	  });
34	
35	  it('December 1st → November', () => {
36	    expect(previousMonthPeriod(new Date('2024-12-01T00:00:00Z'))).toBe('2024-11');
37	  });
38	
39	  it('result is always zero-padded YYYY-MM format', () => {
40	    // September: month 9 → 09
41	    expect(previousMonthPeriod(new Date('2024-10-01T00:00:00Z'))).toMatch(/^\d{4}-\d{2}$/);
42	    expect(previousMonthPeriod(new Date('2024-10-01T00:00:00Z'))).toBe('2024-09');
43	  });
44	
45	  it('uses UTC date, not local time (no TZ ambiguity)', () => {
46	    // Exactly midnight UTC on Feb 1 — should still be Feb 1 in UTC → Jan period
47	    const utcMidnight = new Date('2024-02-01T00:00:00.000Z');
48	    expect(previousMonthPeriod(utcMidnight)).toBe('2024-01');
49	  });
50	});
51	
52	// ── isFirstDayOfMonthUTC ──────────────────────────────────────────────────────
53	
54	describe('isFirstDayOfMonthUTC', () => {
55	  it('returns true on the 1st at midnight UTC', () => {
56	    expect(isFirstDayOfMonthUTC(new Date('2024-03-01T00:00:00Z'))).toBe(true);
57	  });
58	
59	  it('returns true on the 1st at end of day UTC', () => {
60	    expect(isFirstDayOfMonthUTC(new Date('2024-03-01T23:59:59Z'))).toBe(true);
61	  });
62	
63	  it('returns false on the 2nd', () => {
64	    expect(isFirstDayOfMonthUTC(new Date('2024-03-02T00:00:00Z'))).toBe(false);
65	  });
66	
67	  it('returns false on the last day of a month', () => {
68	    expect(isFirstDayOfMonthUTC(new Date('2024-02-29T12:00:00Z'))).toBe(false);
69	  });
70	});
71	
72	// ── SettlementSchedulerService.tick() ────────────────────────────────────────
73	
74	function makeGenerateMonthlyMock() {
75	  return jest.fn(async (period: string, _actorId: string, triggeredBy: string): Promise<GenerationRunResult> => ({
76	    period,
77	    triggeredBy: triggeredBy as any,
78	    generatedCount: 1,
79	    skippedCount: 0,
80	    errorCount: 0,
81	    durationMs: 5,
82	    settlements: [],
83	  }));
84	}
85	
86	function makeScheduler(generateMonthlyFn: jest.Mock) {
87	  const fakeService = { generateMonthly: generateMonthlyFn } as unknown as SettlementsService;
88	  return new SettlementSchedulerService(fakeService);
89	}
90	
91	// tick() accepts an injected `now` date to avoid mocking global.Date
92	const MAR_1 = new Date('2024-03-01T00:00:00Z');
93	const MAR_1_NOON = new Date('2024-03-01T12:00:00Z');
94	const APR_1 = new Date('2024-04-01T00:00:00Z');
95	const JUN_15 = new Date('2024-06-15T10:00:00Z');
96	
97	describe('SettlementSchedulerService.tick()', () => {
98	  it('does not call generateMonthly when today is not the 1st', async () => {
99	    const generate = makeGenerateMonthlyMock();
100	    const sched = makeScheduler(generate);
101	    await sched.tick(JUN_15);
102	    expect(generate).not.toHaveBeenCalled();
103	  });
104	
105	  it('calls generateMonthly with the previous month period when it is the 1st', async () => {
106	    const generate = makeGenerateMonthlyMock();
107	    const sched = makeScheduler(generate);
108	    await sched.tick(MAR_1);
109	    expect(generate).toHaveBeenCalledWith('2024-02', SCHEDULER_ACTOR_ID, 'scheduler');
110	  });
111	
112	  it('passes triggeredBy=scheduler to distinguish from manual calls', async () => {
113	    const generate = makeGenerateMonthlyMock();
114	    const sched = makeScheduler(generate);
115	    await sched.tick(MAR_1);
116	    expect(generate.mock.calls[0][2]).toBe('scheduler');
117	  });
118	
119	  it('does not call generateMonthly a second time for the same period (in-memory dedup)', async () => {
120	    const generate = makeGenerateMonthlyMock();
121	    const sched = makeScheduler(generate);
122	    await sched.tick(MAR_1);       // first tick on the 1st
123	    await sched.tick(MAR_1_NOON);  // second tick, same day same period
124	    expect(generate).toHaveBeenCalledTimes(1);
125	  });
126	
127	  it('triggers again for a new month after a previous month was already generated', async () => {
128	    const generate = makeGenerateMonthlyMock();
129	    const sched = makeScheduler(generate);
130	
131	    await sched.tick(MAR_1); // March 1st → generates Feb
132	    await sched.tick(APR_1); // April 1st → generates March
133	
134	    expect(generate).toHaveBeenCalledTimes(2);
135	    expect(generate.mock.calls[0][0]).toBe('2024-02');
136	    expect(generate.mock.calls[1][0]).toBe('2024-03');
137	  });
138	
139	  it('does not throw when generateMonthly rejects — errors are swallowed', async () => {
140	    const generate = jest.fn().mockRejectedValue(new Error('DB down'));
141	    const sched = makeScheduler(generate);
142	    await expect(sched.tick(MAR_1)).resolves.not.toThrow();
143	  });
144	});
