146	// ── SettlementsService.generateMonthly() — idempotency ───────────────────────
147	
148	function makeVendor(id: string) {
149	  return { id, username: `vendor-${id}`, role: 'vendor', isActive: true };
150	}
151	
152	interface SavedRecord {
153	  vendorId: string;
154	  month: string;
155	  id: string;
156	  status: string;
157	  data: any;
158	}
159	
160	function makeSettlementsService(
161	  vendors: ReturnType<typeof makeVendor>[],
162	  existingRecords: SavedRecord[] = [],
163	) {
164	  const db: SavedRecord[] = [...existingRecords];
165	  let idCounter = 1;
166	
167	  const settlementRepo = {
168	    findOne: jest.fn(({ where }: any) => {
169	      const record = db.find(r => r.vendorId === where.vendorId && r.month === where.month);
170	      return Promise.resolve(record ?? null);
171	    }),
172	    save: jest.fn((entity: any) => {
173	      // Simulate unique constraint violation if duplicate exists
174	      const duplicate = db.find(r => r.vendorId === entity.vendorId && r.month === entity.month);
175	      if (duplicate) {
176	        const err = new Error('duplicate key value violates unique constraint');
177	        (err as any).code = '23505';
178	        return Promise.reject(err);
179	      }
180	      const saved = { ...entity, id: `settlement-${idCounter++}` };
181	      db.push(saved);
182	      return Promise.resolve(saved);
183	    }),
184	    create: jest.fn((e: any) => e),
185	  } as unknown as Repository<any>;
186	
187	  const userRepo = {
188	    find: jest.fn(() => Promise.resolve(vendors)),
189	  } as unknown as Repository<any>;
190	
191	  const listingRepo = {
192	    createQueryBuilder: jest.fn(() => ({
193	      where: jest.fn().mockReturnThis(),
194	      andWhere: jest.fn().mockReturnThis(),
195	      getMany: jest.fn(() => Promise.resolve([])),
196	    })),
197	  } as unknown as Repository<any>;
198	
199	  const rateLimitRepo = {} as unknown as Repository<any>;
200	  const auditService = { log: jest.fn(() => Promise.resolve({})) };
201	  const freightService = { calculate: jest.fn(() => ({ total: 25.0 })) };
202	  const encryption = { decrypt: jest.fn((v: any) => v), encrypt: jest.fn((v: any) => v) };
203	
204	  return new SettlementsService(
205	    settlementRepo,
206	    listingRepo,
207	    userRepo,
208	    auditService as any,
209	    freightService as any,
210	    encryption as any,
211	  );
212	}
