214	describe('SettlementsService.generateMonthly() — idempotency', () => {
215	  it('generates one settlement per vendor on first call', async () => {
216	    const svc = makeSettlementsService([makeVendor('v1'), makeVendor('v2')]);
217	    const result = await svc.generateMonthly('2024-01', 'admin-1', 'manual');
218	    expect(result.generatedCount).toBe(2);
219	    expect(result.skippedCount).toBe(0);
220	  });
