113	  private async processPendingJobs(): Promise<void> {
114	    try {
115	      await this.expireOldJobs();
116	
117	      const runningCount = await this.exportRepo.count({
118	        where: { status: ExportJobStatus.RUNNING },
119	      });
120	      if (runningCount >= MAX_CONCURRENT) return;
121	
122	      const slotsAvailable = MAX_CONCURRENT - runningCount;
123	      const queued = await this.exportRepo.find({
124	        where: { status: ExportJobStatus.QUEUED },
125	        order: { createdAt: 'ASC' },
126	        take: slotsAvailable,
127	      });
128	
129	      for (const job of queued) {
130	        this.processJob(job).catch((err) => {
131	          logger.error(`Export job ${job.id} failed: ${err}`, { context: 'ExportProcessor' });
132	        });
133	      }
134	    } catch (err) {
135	      logger.error(`Export poll error: ${err}`, { context: 'ExportProcessor' });
136	    }
137	  }
