{"file_path": "/home/nahom/Desktop/Others/EaglePointAI/vibe-coding-projects/pet-market-operations-system/repo/frontend/src/pages/Listings.test.tsx", "content": "/**
 * Listings.test.tsx
 *
 * Component-level tests covering:
 *   - Presence of all filter controls (including new region / age / rating inputs)
 *   - Filter interactions dispatch correct query params to the API
 *   - No-results EmptyState renders
 *   - Fallback "Similar Breeds" / "Trending" sections render when the API
 *     returns fallback data alongside an empty item list
 *   - Fallback sections are hidden when the API provides no fallback
 */

import { screen, waitFor, fireEvent } from '@testing-library/react';
import { http, HttpResponse } from 'msw';
import { renderWithProviders } from '../test/test-utils';
import {
  server,
} from '../test/mocks/server';
import {
  API_BASE,
  MOCK_LISTING,
  makeListingsResponse,
} from '../test/mocks/handlers';
import Listings from './Listings';

// ── Module-level mocks ────────────────────────────────────────────────────────

vi.mock('../store/auth.store', () => ({
  useAuthStore: () => ({ role: 'shopper', token: null }),
}));

// Keep react-router-dom real but stub useNavigate so ListingCard clicks don't
// break in jsdom (no real history object).
vi.mock('react-router-dom', async (importOriginal) => {
  const actual = await importOriginal<typeof import('react-router-dom')>();
  return { ...actual, useNavigate: () => vi.fn() };
});

// ── Helpers ───────────────────────────────────────────────────────────────────

/**
 * Override the listings handler for one test, capturing every request URL.
 * Returns a getter so assertions can be deferred with waitFor.
 */
function captureListingsRequests(response: ReturnType<typeof makeListingsResponse>) {
  const urls: string[] = [];
  server.use(
    http.get(`${API_BASE}/listings`, ({ request }) => {
      urls.push(request.url);
      return HttpResponse.json(response);
    }),
  );
  return () => urls;
}

// ── Filter presence ───────────────────────────────────────────────────────────

describe('Listings — filter sidebar controls are rendered', () => {
  it('renders the search text input', () => {
    renderWithProviders(<Listings />);
    expect(screen.getByPlaceholderText('Search listings...')).toBeInTheDocument();
  });

  it('renders the breed select', () => {
    renderWithProviders(<Listings />);
    expect(screen.getByRole('option', { name: 'All Breeds' })).toBeInTheDocument();
  });

  it('renders the region text input', () => {
    renderWithProviders(<Listings />);
    expect(screen.getByPlaceholderText('Region')).toBeInTheDocument();
  });

  it('renders the min age input', () => {
    renderWithProviders(<Listings />);
    expect(screen.getByPlaceholderText('Min age')).toBeInTheDocument();
  });

  it('renders the max age input', () => {
    renderWithProviders(<Listings />);
    expect(screen.getByPlaceholderText('Max age')).toBeInTheDocument();
  });

  it('renders the min rating input', () => {
    renderWithProviders(<Listings />);
    expect(screen.getByPlaceholderText('Min ★')).toBeInTheDocument();
  });

  it('renders the max rating input', () => {
    renderWithProviders(<Listings />);
    expect(screen.getByPlaceholderText('Max ★')).toBeInTheDocument();
  });

  it('renders the min / max price inputs', () => {
    renderWithProviders(<Listings />);
    expect(screen.getByPlaceholderText('Min $')).toBeInTheDocument();
    expect(screen.getByPlaceholderText('Max $')).toBeInTheDocument();
  });

  it('renders Apply Filters and Reset buttons', () => {
    renderWithProviders(<Listings />);
    expect(screen.getByRole('button', { name: /apply filters/i })).toBeInTheDocument();
    expect(screen.getByRole('button', { name: /reset/i })).toBeInTheDocument();
  });
});

// ── Filter → API param propagation ───────────────────────────────────────────

describe('Listings — filter changes send correct params to the API', () => {
  it('region filter includes region query param', async () => {
    const getUrls = captureListingsRequests(makeListingsResponse([MOCK_LISTING]));
    renderWithProviders(<Listings />);

    // Wait for the initial request to land before acting on the filter
    await waitFor(() => expect(getUrls().length).toBeGreaterThan(0));
    const initialCount = getUrls().length;

    fireEvent.change(screen.getByPlaceholderText('Region'), {
      target: { value: 'Texas' },
    });

    await waitFor(() => {
      expect(getUrls().length).toBeGreaterThan(initialCount);
      const latest = new URL(getUrls().at(-1)!);
      expect(latest.searchParams.get('region')).toBe('Texas');
    });
  });

  it('minAge filter includes minAge query param', async () => {
    const getUrls = captureListingsRequests(makeListingsResponse([MOCK_LISTING]));
    renderWithProviders(<Listings />);

    await waitFor(() => expect(getUrls().length).toBeGreaterThan(0));
    const initialCount = getUrls().length;

    fireEvent.change(screen.getByPlaceholderText('Min age'), {
      target: { value: '6' },
    });

    await waitFor(() => {
      expect(getUrls().length).toBeGreaterThan(initialCount);
      const latest = new URL(getUrls().at(-1)!);
      expect(latest.searchParams.get('minAge')).toBe('6');
    });
  });

  it('maxAge filter includes maxAge query param', async () => {
    const getUrls = captureListingsRequests(makeListingsResponse([MOCK_LISTING]));
    renderWithProviders(<Listings />);

    await waitFor(() => expect(getUrls().length).toBeGreaterThan(0));
    const initialCount = getUrls().length;

    fireEvent.change(screen.getByPlaceholderText('Max age'), {
      target: { value: '24' },
    });

    await waitFor(() => {
      expect(getUrls().length).toBeGreaterThan(initialCount);
      const latest = new URL(getUrls().at(-1)!);
      expect(latest.searchParams.get('maxAge')).toBe('24');
    });
  });

  it('minRating filter includes minRating query param', async () => {
    const getUrls = captureListingsRequests(makeListingsResponse([MOCK_LISTING]));
    renderWithProviders(<Listings />);

    await waitFor(() => expect(getUrls().length).toBeGreaterThan(0));
    const initialCount = getUrls().length;

    fireEvent.change(screen.getByPlaceholderText('Min ★'), {
      target: { value: '4' },
    });

    await waitFor(() => {
      expect(getUrls().length).toBeGreaterThan(initialCount);
      const latest = new URL(getUrls().at(-1)!);
      expect(latest.searchParams.get('minRating')).toBe('4');
    });
  });

  it('maxRating filter includes maxRating query param', async () => {
    const getUrls = captureListingsRequests(makeListingsResponse([MOCK_LISTING]));
    renderWithProviders(<Listings />);

    await waitFor(() => expect(getUrls().length).toBeGreaterThan(0));
    const initialCount = getUrls().length;

    fireEvent.change(screen.getByPlaceholderText('Max ★'), {
      target: { value: '5' },
    });

    await waitFor(() => {
      expect(getUrls().length).toBeGreaterThan(initialCount);
      const latest = new URL(getUrls().at(-1)!);
      expect(latest.searchParams.get('maxRating')).toBe('5');
    });
  });

  it('minPrice filter includes minPrice query param', async () => {
    const getUrls = captureListingsRequests(makeListingsResponse([MOCK_LISTING]));
    renderWithProviders(<Listings />);

    await waitFor(() => expect(getUrls().length).toBeGreaterThan(0));
    const initialCount = getUrls().length;

    fireEvent.change(screen.getByPlaceholderText('Min $'), {
      target: { value: '500' },
    });

    await waitFor(() => {
      expect(getUrls().length).toBeGreaterThan(initialCount);
      const latest = new URL(getUrls().at(-1)!);
      expect(latest.searchParams.get('minPrice')).toBe('500');
    });
  });
});

// ── No-results + fallback block ───────────────────────────────────────────────

describe('Listings — no-results fallback rendering', () => {
  it('shows EmptyState when items array is empty', async () => {
    captureListingsRequests(makeListingsResponse([]));
    renderWithProviders(<Listings />);

    await waitFor(() =>
      expect(screen.getByText(/no listings found/i)).toBeInTheDocument(),
    );
  });

  it('shows "Similar Breeds" section when fallback.similarBreed has items', async () => {
    captureListingsRequests(
      makeListingsResponse([], {
        similarBreed: [MOCK_LISTING],
        trending: [],
      }),
    );
    renderWithProviders(<Listings />);

    await waitFor(() =>
      expect(screen.getByText(/similar breeds/i)).toBeInTheDocument(),
    );
    // The fallback listing title should appear in that section
    expect(screen.getByText('Golden Retriever Puppy')).toBeInTheDocument();
  });

  it('shows "Trending This Week" section when fallback.trending has items', async () => {
    captureListingsRequests(
      makeListingsResponse([], {
        similarBreed: [],
        trending: [{ ...MOCK_LISTING, id: 'trending-1', title: 'Trending Puppy' }],
      }),
    );
    renderWithProviders(<Listings />);

    await waitFor(() =>
      expect(screen.getByText(/trending this week/i)).toBeInTheDocument(),
    );
    expect(screen.getByText('Trending Puppy')).toBeInTheDocument();
  });

  it('hides "Similar Breeds" when fallback.similarBreed is empty', async () => {
    captureListingsRequests(
      makeListingsResponse([], { similarBreed: [], trending: [] }),
    );
    renderWithProviders(<Listings />);

    await waitFor(() =>
      expect(screen.getByText(/no listings found/i)).toBeInTheDocument(),
    );
    expect(screen.queryByText(/similar breeds/i)).not.toBeInTheDocument();
  });

  it('shows no fallback sections when the API returns no fallback field', async () => {
    captureListingsRequests(makeListingsResponse([]));
    renderWithProviders(<Listings />);

    await waitFor(() =>
      expect(screen.getByText(/no listings found/i)).toBeInTheDocument(),
    );
    expect(screen.queryByText(/similar breeds/i)).not.toBeInTheDocument();
    expect(screen.queryByText(/trending this week/i)).not.toBeInTheDocument();
  });
});
"}

