// ── Auth seed ─────────────────────────────────────────────────────────────────

function seedSession(role = 'shopper') {
  useAuthStore.setState({
    user: { id: 'user-1', username: 'testuser', email: 'u@test.com', role },
    token: 'mock-token',
    role,
  });
